INSERT INTO public.photos VALUES (21439, 'Gabriel Faci Abad c.1910', 'Imagen del quâ”śÂˇmico Gabriel Faci Abad posiblemente capturada por su hermano Miguel en el laboratorio de la botica que regentaba en el nâ”¬â•‘ 94 del tramo medio del Coso. Paralelamente, Gabriel ejercâ”śÂˇa de fiel contraste en la joyerâ”śÂˇa de sus hermanos Miguel y Pedro, estampando con un punzâ”śâ”‚n personalizado la marca que garantizaba la genuina procedencia del artâ”śÂˇculo en cuestiâ”śâ”‚n. Gabriel tambiâ”śÂ®n era fotâ”śâ”‚grafo aficionado, si bien no se prodigâ”śâ”‚ tanto como su hermano Miguel, y fue junto a â”śÂ®l miembro del grupo fundador de la Sociedad Fotogrâ”śĂ­fica de Zaragoza. Fuente visual: Archivo Gabriel Faci Abad, en AHPZ', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65140000, -0.87895800, '0101000020E610000099D711876C20ECBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45493144901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45493144901.webp', 'https://www.flickr.com/photos/zaragozaantigua/45493144901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21482, 'Vista parcial 1925', 'Postal, 1925. Fotografâ”śÂˇa de parte de la antigua ciudad, tomada desde la torre de San Gil.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958326126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958326126.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958326126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21524, 'Coso Medio 1926', 'Imagen de la casa de Mariano Garcâ”śÂˇa (actual Coso nâ”¬â•‘ 51-53), diseâ”śâ–’o de Regino Borobio sobre el solar de dos antiguos edificios piqueteados, en formas similares a los que en la imagen le flanquean. En su momento esta moderna casa destacaba por su altura, aunque el posterior piqueteo de su vecino de la derecha, y sustituciâ”śâ”‚n por la cosa que hoy se levanta ahâ”śÂˇ (Coso nâ”¬â•‘ 55), le ha dejado casi como una referencia clâ”śĂ­sica en esa parte del Coso. Tampoco â”śÂ®l se ha librado de las "reformas", como su parte inferior actual (planta calle), que parece haber sido abducida por el horror de su derecha. Fuente visual: "Una mirada a travâ”śÂ®s de la arquitectura: Regino y Josâ”śÂ® Borobio Ojeda", Daniel Estabâ”śÂ®n Boldova.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65173400, -0.87958300, '0101000020E61000001EC3633F8B25ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16971021878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16971021878.webp', 'https://www.flickr.com/photos/zaragozaantigua/16971021878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21550, 'Coso Medio 1926', 'Instalaciâ”śâ”‚n de lâ”śÂˇnea telefâ”śâ”‚nica en la redacciâ”śâ”‚n del Diario de Avisos, comprado por Heraldo de Aragâ”śâ”‚n y luego sede de su imprenta, en el Coso Medio de Zaragoza, esquina con la calle de Santa Catalina (izquierda). A la derecha, el colegio de las Hermanas de la Caridad de Santa Ana. Fuente visual: Fundaciâ”śâ”‚n Telefâ”śâ”‚nica.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65142900, -0.87866000, '0101000020E610000020B58993FB1DECBF3F55850662D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20749387638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20749387638.webp', 'https://www.flickr.com/photos/zaragozaantigua/20749387638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21557, 'Calle Porcell 1926', 'Instalaciâ”śâ”‚n de la lâ”śÂˇnea telefâ”śâ”‚nica en el Coso Medio, a la altura de la calle de Juan Porcell. Bajo las escaleras, la bombonerâ”śÂˇa-cafeterâ”śÂˇa-chocolaterâ”śÂˇa "Cesaraugusta". Al fondo, tras el hotel restaurant Florida, entrada por el Coso del colegio de las Hermanas de la Caridad de Santa Ana. Fuente visual : Fundaciâ”śâ”‚n Telefâ”śâ”‚nica.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65150100, -0.87910000, '0101000020E6100000363CBD529621ECBFD927806264D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21584275702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21584275702.webp', 'https://www.flickr.com/photos/zaragozaantigua/21584275702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21607, 'San Gil c.1926', 'Imagen de la iglesia parroquial del Seâ”śâ–’or San Gil Abad, capturada a cierta altura, posiblemente desde el antiguo nâ”¬â•‘ 3 de la calle Ossau. Desde este emplazamiento el fotâ”śâ”‚grafo ha conseguido una buena visual del lado norte del templo, recayente a la calle de los Estâ”śÂ®banes, con la destacada y emergente fâ”śĂ­brica mudâ”śÂ®jar de la torre. Al principio del diez y ocho siglo, la orientaciâ”śâ”‚n de la iglesia fue modificada para que la entrada principal recayese en la "calle nueba de San Gil", luego don Jaime I. Fuente visual: Estudio Coyne (AHPZ-DARA)', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65287200, -0.87950800, '0101000020E6100000744012F6ED24ECBFB03C484F91D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28436949991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28436949991.webp', 'https://www.flickr.com/photos/zaragozaantigua/28436949991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21639, 'Coso Medio 1923', 'Fotografâ”śÂˇa editada como postal promocional del dueto artâ”śÂˇstico "Adriana y su Charlot", hijas del reputado acrâ”śâ”‚bata seâ”śâ–’or Borza e integrantes del Circo Americano de Madrid, durante su paso por Zaragoza en el Teatrto Circo. La captura se ha realizado en Photo Greco, en el nâ”¬â•‘ 61 del tramo medio del Coso, junto al Teatro Principal, donde daba sus primeros pasos el estudio fotogrâ”śĂ­fico de Manuel Marâ”śÂˇn Chivite.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65193500, -0.87962500, '0101000020E6100000D9CEF753E325ECBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50911850992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50911850992.webp', 'https://www.flickr.com/photos/zaragozaantigua/50911850992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21643, 'Miguel Primo de Rivera 1927', 'Imagen capturada en la puerta del Teatro Principal a la salida del marquâ”śÂ®s de Estella, general Miguel Primo de Rivera que en su calidad de presidente del Consejo de ministros visitâ”śâ”‚ Zaragoza y otros municipios aragoneses en el mes de agosto de 1927. Junto al marquâ”śÂ®s-general-presidente-dictador posa el alcalde Miguel Alluâ”śÂ® Salvador, que en nombre del Ayuntamiento le habâ”śÂˇa obsequiado con un "refresco" al que asistieron las principales autoridades religiosas, militares y civiles de la ciudad. Antes del refresco, habâ”śÂˇa sido informado de varios proyectos urbanâ”śÂˇsticos: el abastecimiento de aguas a la Academia General Militar, el Gran Hotel y el ensanche de la ciudad.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65186300, -0.87952800, '0101000020E61000003B527DE71725ECBF793C2D3F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51211956799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51211956799.webp', 'https://www.flickr.com/photos/zaragozaantigua/51211956799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21701, 'Colegio del Pilar aâ”śâ–’os 30', 'Colegio Politâ”śÂ®cnico Nuestra Seâ”śâ–’ora del Pilar. Detalle de la portada. En 1930 aparece domiciliado en Mâ”śÂ®ndez Nâ”śâ•‘â”śâ–’ez 36 de Zaragoza, con "Alumnos internos, medio-pensionistas, y vigilados", de "gran confort", e incluso con director espiritual. Internado a cargo de "Reverendos Sacerdotes". En 1968 se concede autorizaciâ”śâ”‚n para impartir enseâ”śâ–’anza a un centro de la misma denominaciâ”śâ”‚n en la avenida Clavâ”śÂ® 43-53, que ya funcionaba como tal desde finales de los aâ”śâ–’os cincuenta. Fuente visual: www.todocoleccion.net/', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65325000, -0.87875500, '0101000020E6100000904946CEC21EECBF560E2DB29DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15676405255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15676405255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15676405255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21931, 'Jefe del Estado 1946', 'Ayuntamiento de Zaragoza/Ortiz. Calle Cruz, 16 (Madrid). 15 de diciembre de 1946. "El Jefe del Estado, Francisco Franco, dirige la palabra desde el balcâ”śâ”‚n del Teatro Principal." Al fondo de la imagen, en la Plaza de Espaâ”śâ–’a, destaca el vacâ”śÂˇo donde deberâ”śÂˇa estar la DPZ. Un aâ”śâ–’o antes se habâ”śÂˇa piqueteado el edificio levantado a mediados del XIX. Teodoro Râ”śÂˇos presentâ”śâ”‚ un proyecto para sustituirlo. En 1950 fue anunciada (y celebrada con campanas) su finalizaciâ”śâ”‚n, aunque las obras no terminaron hasta 1952. Al fondo de la Plaza de Espaâ”śâ–’a, la câ”śâ•‘pula de Santiago el Mayor.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65180700, -0.87939400, '0101000020E6100000548EC9E2FE23ECBFE5266A696ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936159321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936159321.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936159321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21989, 'Coso Medio 1946', 'Imagen capturada en el balcâ”śâ”‚n del Teatro Principal durante la visita de Su Excelencia el Jefe del Estado, Generalâ”śÂˇsimo Franco, Victorioso Caudillo de los Ejâ”śÂ®rcitos de Tierra, Mar y Aire, el 15 de diciembre de 1946. Esta visual del tramo medio del Coso nos ofrece una buena perspectiva de câ”śâ”‚mo de provinciana y poco moderna era su fachada desde la casa de la Asociaciâ”śâ”‚n de Labradores de Zaragoza, a la izquierda, junto al ferrolano, hasta casi la calle de los Sitios, pasando por los emboques a las calles de Santa Catalina, Juan Porcell, y Jerâ”śâ”‚nimo Blancas. El posterior "Desarrollismo", y "post-Desarrollismo", enmendaron esto. Fuente visual: Ortiz, AMZ, sig. 12933', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65150100, -0.87910000, '0101000020E6100000363CBD529621ECBFD927806264D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30318701771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30318701771.webp', 'https://www.flickr.com/photos/zaragozaantigua/30318701771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22050, 'Calle de Zabala 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Zabala." Esta calle conectaba Don Jaime I con la calle de Verâ”śâ”‚nica, por las traseras del Teatro Principal. Con el derribo de la manzana de viviendas entre esta calle, la de Verâ”śâ”‚nica, y Don Jaime I, en 1966 la calle Zabala desapareciâ”śâ”‚ y dio lugar a la Plaza de "Sinuâ”śÂ®s Urbiola". En la imagen, aspecto de la calle tomada desde Don Jaime I. El Teatro Principal se encuentra a la derecha. A la izquierda, un poco mâ”śĂ­s adelante, la calle de San Andrâ”śÂ®s. Al fondo, la calle de Verâ”śâ”‚nica.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65240800, -0.87944200, '0101000020E61000009752978C6324ECBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14883251457.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14883251457.webp', 'https://www.flickr.com/photos/zaragozaantigua/14883251457/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25972, 'Feria de Muestras 1975', 'Recinto de la Feria de Muestras, en una vista aâ”śÂ®rea con sus espacios y pabellones en plena ocupaciâ”śâ”‚n durante la Feria Internacional de Maquinaria Agrâ”śÂˇcola, que se celebraba desde 1964. Desde la ediciâ”śâ”‚n de 1970 se utilizaban los exteriores del recinto, por superarse su capacidad en el interior. La FIMA de 1975 tuvo una fuerte orientaciâ”śâ”‚n a la explotaciâ”śâ”‚n ganadera. En 1987 pasâ”śâ”‚ a celebrarse en las mâ”śĂ­s amplias instalaciones de la nueva Feria de Muestras, inauguradas el aâ”śâ–’o anterior en la carretera de Madrid, frente a la Venta de los Caballos. Al fondo y a la derecha, vista del cuartel de Palafox, edificado en 1926 y que pasâ”śâ”‚ a propiedad municipal en 1979 durante la Operaciâ”śâ”‚n Cuarteles, en un proceso que culminâ”śâ”‚ en 1985, siendo utilizado luego como sede de las escuelas municipales de Mâ”śâ•‘sica, Danza y Teatro, el archivo de la Filmoteca o el centro câ”śÂˇvico Universidad.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084794911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084794911.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084794911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22065, 'Coso Medio 1953', 'Fachada del Banco de Santander, sito en la calle del Coso. A finales del XVIII se edificâ”śâ”‚ en esta ubicaciâ”śâ”‚n la casa de Simâ”śâ”‚n Ignacio Tarazona, con diseâ”śâ–’o de Agustâ”śÂˇn Sanz Alâ”śâ”‚s, que despuâ”śÂ®s acogiâ”śâ”‚ el edificio de la Capitanâ”śÂˇa General, y desde 1875 fue sede de la sucursal del Banco de Espaâ”śâ–’a en Zaragoza. Cuando el Banco de Espaâ”śâ–’a se trasladâ”śâ”‚ a su actual ubicaciâ”śâ”‚n, el edificio fue derribado en 1940, y sobre el solar se edificâ”śâ”‚, segâ”śâ•‘n proyecto del arquitecto Teodoro Râ”śÂˇos Balaguer, la sede del que se llamâ”śâ”‚ Banco Aragonâ”śÂ®s de Crâ”śÂ®dito, inaugurado el 2 de octubre de 1945. En 1951 el Banco de Santander comprâ”śâ”‚ la finca instalando allâ”śÂˇ su sucursal, reformâ”śĂ­ndose el edificio en 1953 con proyecto de Regino Borobio. Estâ”śĂ­ construido con fachada a dos calles y chaflâ”śĂ­n curvo, con ladrillo visto y revocado, aplacado de piedra, y es una muestra del eclecticismo de lenguaje clasicista de los edificios destinados a sedes bancarias en los aâ”śâ–’os veinte del siglo idem. En la imagen, chaflâ”śĂ­n del banco desde el Coso Medio. A la izquierda, la calle Eusebio Blasco, por donde se mete el tranvâ”śÂˇa de la lâ”śÂˇnea 13 "San Josâ”śÂ®" para dar la vuelta. Mâ”śĂ­s al fondo, la estrecha calle de la Verâ”śâ”‚nica.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65175100, -0.87911000, '0101000020E610000019C5724BAB21ECBF5111A7936CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061455910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061455910.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061455910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22066, 'Calle de la Verâ”śâ”‚nica 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Verâ”śâ”‚nica." En la imagen, aspecto de la calle de Verâ”śâ”‚nica cuando, al objeto de ensanchar la calle, empezaban los derribos de los nâ”śâ•‘meros de la izquierda. Esta calle desembocaba, al fondo, en la Plaza de la Verâ”śâ”‚nica.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65193500, -0.87819800, '0101000020E610000016342DB1321AECBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15069672062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15069672062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15069672062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22104, 'Calle de Valentâ”śÂˇn Zabala 1955', 'Tranvâ”śÂˇa de la lâ”śÂˇnea 1 Bajo Aragâ”śâ”‚n, a su paso por la calle de Valentâ”śÂˇn Zabala de Zaragoza, en 1955. Proviene de la calle Verâ”śâ”‚nica. A la derecha toldo en las traseras del Teatro Principal. La manzana de la izquierda serâ”śĂ­ derribada en 1966 para dar paso a la plaza de Josâ”śÂ® Sinuâ”śÂ®s y Urbiola.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65230400, -0.87912600, '0101000020E6100000850662D9CC21ECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20716420481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20716420481.webp', 'https://www.flickr.com/photos/zaragozaantigua/20716420481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22118, 'Don de Don Jaime I c.1955', 'Imagen granulada de operaciones de asfaltado en la calle Don Jaime I, con vistas a su conversiâ”śâ”‚n en una mini-autovâ”śÂˇa de acceso para el trâ”śĂ­fico rodado, desde el puente de Piedra y hasta el centro de la ciudad. A la derecha, emboque a la calle San Jorge, con visual de los edificios entre la calle Refugio y Don Jaime I que, un par de dâ”śÂ®cadas despuâ”śÂ®s serâ”śÂˇan derribados y sustituidos, por otras cosas mâ”śĂ­s modernas y menos provincianas. A la izquierda, la calle de Casto Mâ”śÂ®ndez Nâ”śâ•‘â”śâ–’ez. Al fondo, la plaza de Ariâ”śâ–’o. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65319400, -0.87848700, '0101000020E6100000C2C1DEC4901CECBFC2F869DC9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500524178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500524178.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500524178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22121, 'Calle Estâ”śÂ®banes 1956', 'Ricardo Garcâ”śÂˇa, joven botijero de Salvatierra de los Barros (Badajoz), expone su mercancâ”śÂˇa junto a la iglesia de San Gil, en mayo de 1956. Es el hijo de Manuel, que lleva 18 primaveras viajando a pie a Zaragoza con los botijos en el borrico. Al fondo, el cine Latino, en el 29 de la calle Estâ”śÂ®banes, inaugurado en febrero de 1954, especializado en reestrenos y cerrado en agosto de 1979. Fuente: Heraldo de Aragâ”śâ”‚n.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22538515441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22538515441.webp', 'https://www.flickr.com/photos/zaragozaantigua/22538515441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22209, 'Calle de la Verâ”śâ”‚nica 1951', 'Imagen capturada en el tramo medio del final de la calle de la Verâ”śâ”‚nica y orientada hacia las calles de Pardo Sastrâ”śâ”‚n, primero, y de Eusebio Blasco, al fondo, desde donde la luz del sol ilumina levemente esta recoleta y antigua calle asociada a la "mala vida" de tascas y prostituciâ”śâ”‚n de las clases bajas. La "mala vida" de las clases altas, refinada, adinerada y radicada en otras zonas de la ciudad, no tenâ”śÂˇa la misma prensa y apenas visibilidad social. Las pequeâ”śâ–’as viviendas de la derecha mantenâ”śÂˇan oculto, como sucedâ”śÂˇa desde la Alta Edad Media, el que fuera teatro romano de la ciudad. Tras ellas finalizaba en fondo de saco la zigzagueante calle de Gabriel Zaporta, con inicio en la de San Jorge. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65186500, -0.87798200, '0101000020E6100000E6400FB56D18ECBF1A34F44F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41362743101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41362743101.webp', 'https://www.flickr.com/photos/zaragozaantigua/41362743101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22210, 'Calle de la Verâ”śâ”‚nica 1951', 'Imagen capturada entre las tinieblas del tramo final de la recoleta calle de la Verâ”śâ”‚nica, que flanqueado por un par de pardales que posan entre claroscuros se corresponde con el de los antiguos nâ”śâ•‘meros 41 a 47 (izquierda) y 40 a 46 (derecha). La curva hacia la izquierda del final de la calle se ajusta bastante con el semicircular perfil de la cavea o graderâ”śÂˇo del subterrâ”śĂ­neo teatro romano, sepultado e ignoto desde la Alta Edad Media. Al fondo, luminosa, la plazuela de la Verâ”śâ”‚nica, con vista parcial del inmueble del nâ”śâ•‘mero 5. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65175300, -0.87770300, '0101000020E61000001D3C139A2416ECBFF2086EA46CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42710629965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42710629965.webp', 'https://www.flickr.com/photos/zaragozaantigua/42710629965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22240, 'Coso Medio, 1953', 'Imagen capturada en la recepciâ”śâ”‚n del Banco de Santander sito en la calle Coso nâ”¬â•‘ 59 donde estuviera la ilustrada casa de Simâ”śâ”‚n Ignacio Tarazona, que despuâ”śÂ®s acogiâ”śâ”‚ el edificio de la Capitanâ”śÂˇa General y desde 1875 fue sucursal del Banco de Espaâ”śâ–’a. Cuando el Banco de Espaâ”śâ–’a se trasladâ”śâ”‚ a su actual sede, la antigua casa fue derribada y sobre su solar se edificâ”śâ”‚ segâ”śâ•‘n proyecto del arquitecto Teodoro Râ”śÂˇos Balaguer, la sede del Banco Aragonâ”śÂ®s de Crâ”śÂ®dito, inaugurado el 2 de octubre de 1945. En 1951 el Banco de Santander comprâ”śâ”‚ la finca instalando allâ”śÂˇ su sucursal principal, reformâ”śĂ­ndose el edificio en 1953 con proyecto de Regino Borobio. Tras la puerta giratoria del fondo, entrada desde el Coso. A la derecha, la esquina con la calle Eusebio Blasco.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65174300, -0.87918500, '0101000020E6100000C347C4944822ECBFCF328B506CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51022502263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51022502263.webp', 'https://www.flickr.com/photos/zaragozaantigua/51022502263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22253, 'Iglesia de San Juan y San Pedro 1966', 'Espectral imagen de la torre mudâ”śÂ®jar de la antigua Iglesia de San Juan y San Pedro, tomada desde la esquina de la calle Refugio con la calle San Juan y San Pedro. Levantada en el siglo XIV, casi enfrente a las antiguas Termas Romanas, de factura modesta, en ladrillo y tapial, pero con una envidiable decoraciâ”śâ”‚n mudâ”śÂ®jar. Cuando se tomâ”śâ”‚ esta imagen, la iglesia ya estaba abandonada y cerrada, a la espera de la piqueta, que llegâ”śâ”‚ este aâ”śâ–’o 1966. Era la quinta torre mudâ”śÂ®jar de la ciudad, tras la Magdalena, San Miguel, San Pablo, y San Gil. Hoy es sâ”śâ”‚lo otro bloque de viviendas mâ”śĂ­s.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65330600, -0.87756500, '0101000020E6100000DBA7E3310315ECBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14663965189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14663965189.webp', 'https://www.flickr.com/photos/zaragozaantigua/14663965189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22397, 'San Gil 1966', 'Puerta de la iglesia parroquial de San Gil, en la calle Don Jaime I. Fuente visual: Foto Leonardo Pâ”śÂ®rez Obis, donada por â”śĂĽngel Hernâ”śĂ­ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22834691510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22834691510.webp', 'https://www.flickr.com/photos/zaragozaantigua/22834691510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22604, 'Calle Santa Catalina 1973', 'Foto Monge, 1973. Imagen tomada con motivo del inminente derribo del edificio del Coso 84, esquina con la calle de Santa Catalina. La empresa encargada de levantar el monstruoso bloque que lo sustituye se denominaba, muy adecuadamente, "Marvel". Este emplazamiento, que vemos aquâ”śÂˇ desde la calle de Santa Catalina, con el Coso Medio al fondo, fue domicilio del Conde de Aranda, en una edificaciâ”śâ”‚n anterior. Fuente: Diario Amanecer, 17 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65122100, -0.87857400, '0101000020E61000007CB5A338471DECBFF5BBB0355BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18782958384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18782958384.webp', 'https://www.flickr.com/photos/zaragozaantigua/18782958384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22624, 'Santa Catalina 1978', 'Imagen del arranque de la calle Santa Catalina desde el Coso Medio (al fondo), con interesante visual de la original anchura de esta calle, similar a la de sus vecinas de la antigua Juderâ”śÂˇa Nueva, todas reincidentes en el poco ojo de quienes las trazaron, sin pensar en las necesidades de movilidad de la circulaciâ”śâ”‚n rodada a motor de explosiâ”śâ”‚n. Otro elemento de interâ”śÂ®s son las traseras del antiguo nâ”¬â•‘ 100 del Coso, edificio de viviendas con notable patio interior tipo "corrala", y que en sus bajos albergara las imprentas de algunos diarios de la ciudad, el â”śâ•‘ltimo, el mâ”śĂ­s antiguo de la regiâ”śâ”‚n aragonesa. Justo a su izquierda estaba el nâ”¬â•‘ 96-98, que daba acceso al colegio de las Hijas de la Caridad de Santa Ana, que vemos a la izquierda, en lo que fue su primera ampliaciâ”śâ”‚n realizada en 1929, que llegaba hasta la mitad de la calle Santa Catalina, ya alineada con la que serâ”śÂˇa la nueva anchura de toda la calle. A finales de los aâ”śâ–’os 50, este colegio se ampliarâ”śÂˇa una vez mâ”śĂ­s, hasta la calle San Miguel. Como ya no tenâ”śÂˇa sitio para mâ”śĂ­s ampliaciones, un aâ”śâ–’o antes de esta imagen dejâ”śâ”‚ este enclave, y se fue junto al Canal Imperial, a un espacio de algo mâ”śĂ­s de 4 Ha. de extensiâ”śâ”‚n. Al fondo, la fachada del Coso Medio correspondiente a los nâ”śâ•‘meros 75-85, en la manzana entre las calles Pardo Sastrâ”śâ”‚n (izquierda) y Pedro Joaquâ”śÂˇn Soler (derecha), estâ”śĂ­ viviendo su propia "transiciâ”śâ”‚n" de edificaciones. A la derecha, un pedacito del metâ”śĂ­lico revestimiento de la balconada del recientâ”śÂˇsimo y modernâ”śÂˇsimo edificio nâ”¬â•‘ 84 del Coso, edificado en parte de lo que fuera la casa-palacio de los Climentes, luego de Aranda.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65122100, -0.87857400, '0101000020E61000007CB5A338471DECBFF5BBB0355BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19803380318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19803380318.webp', 'https://www.flickr.com/photos/zaragozaantigua/19803380318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22748, 'Caja de Zaragoza 1970', 'Imagen publicitaria de la sede central de la Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”śâ”‚n y Rioja, en el chaflâ”śĂ­n entre las calles de San Jorge y San Andrâ”śÂ®s. Fue levantada en 1913 segâ”śâ•‘n proyecto de Ramâ”śâ”‚n Cortâ”śĂ­zar y Luis Elizalde de 1910. En 1980, la sede central de la entidad pasâ”śâ”‚ a la plaza de Paraâ”śÂˇso, quedando este inmueble como agencia urbana. Fuente visual: fondohistorico.ceca.es/', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65291000, -0.87800700, '0101000020E61000001E17D522A218ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32534486640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32534486640.webp', 'https://www.flickr.com/photos/zaragozaantigua/32534486640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22783, 'Calle de Mâ”śÂ®ndez Nâ”śâ•‘â”śâ–’ez 1979', 'Imagen capturada desde el arranque de la calle de San Fâ”śÂ®lix y centrada en los restos de la portada del antiguo edificio donde estuviera ubicado el Colegio Politâ”śÂ®cnico Virgen del Pilar, en la calle de Casto Mâ”śÂ®ndez Nâ”śâ•‘â”śâ–’ez nâ”¬â•‘ 36, luego nâ”¬â•‘ 34. Como indica la fotografâ”śÂˇa, la portada de ingreso perduraba todavâ”śÂˇa como reliquia de una singular casona dieciochesca ya derribada. Aâ”śâ–’os despuâ”śÂ®s, a finales de la dâ”śÂ®cada de los ochenta, esta zona serâ”śÂˇa reedificada integralmente con modernos edificios de vivienda. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65349300, -0.87898000, '0101000020E61000008DD13AAA9A20ECBF1C959BA8A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37898747514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37898747514.webp', 'https://www.flickr.com/photos/zaragozaantigua/37898747514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22809, 'Calle de Santa Catalina 1973', 'Inâ”śÂ®dita imagen capturada tras el derribo del antiguo inmueble del nâ”¬â•‘ 84 del tramo medio del Coso, con una gran zona recayente a la calle de Santa Catalina, desde donde se ha tomado la fotografâ”śÂˇa. En primer tâ”śÂ®rmino, ingreso al garito que con el nombre de "El Cortijo", formaba parte de la original "senda de los elefantes" junto con establecimientos como la cervecerâ”śÂˇa alemana Heidelberg, y bares como La Patata Brava, el Chipâ”śÂ®n y el San Miguel, toda una mini-zona de la â”śÂ®poca en este entorno entre el Coso y la calle de San Miguel. Este gran solar formâ”śâ”‚ parte en su tiempo de la gran casa de los Climent, luego propiedad del conde de Aranda. Al fondo, vista parcial del Coso donde a la izquierda se nos muestra parcialmente el antiguo inmueble del nâ”¬â•‘ 75, luego derribado para conformar un enorme bloque tan moderno como descontextualizado, tal y como sucederâ”śÂˇa con el edificio aquâ”śÂˇ levantado por la constructora Marvel, que hoy nos sigue recordando câ”śâ”‚mo se hacâ”śÂˇan las cosas en Zaragoza, urbanâ”śÂˇsticamente hablando, en la terrible dâ”śÂ®cada de los aâ”śâ–’os 70. Sobre ella y al fondo, emerge el bloque del nâ”¬â•‘ 77 del Coso, que ya antes habâ”śÂˇa sustituido a la antigua gran casa de los Pâ”śÂ®rez de Nueros, marqueses de Campo Olivar.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65092500, -0.87878800, '0101000020E61000007FC00303081FECBF0C93A98251D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51538852010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51538852010.webp', 'https://www.flickr.com/photos/zaragozaantigua/51538852010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21235, 'Molino de Goicoechea 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 14, Zaragoza 1908 - Centenario de los Sitios", 1907. "Situado en la ronda, junto a la margen izquierda del Huerva, fue punto muy estratâ”śÂ®gico para contener el movimiento merodeador de los franceses. En la jornada sangrienta del 27 de enero de 1809, las tropas enemigas lograron apoderarse del molino." Molino de aceite de Juan de Goicoechea (1789), en los terrenos del actual Parque Bruil, donde se conservan algunos de sus restos. Fuente: www.pasapues.es', 1907, 1907, 1907, 'Anos 1900', 'LAS FUENTES', 41.64921700, -0.86857500, '0101000020E610000041F163CC5DCBEBBFED80EB8A19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19581115365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19581115365.webp', 'https://www.flickr.com/photos/zaragozaantigua/19581115365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22811, 'Coso Medio 1973', 'Imagen centrada en la esquina del tramo medio del Coso con la calle Eusebio Blasco, donde destaca un estacional puesto de castaâ”śâ–’era instalado junto al telâ”śÂ®fono de la parada de "automâ”śâ”‚viles de punto" o taxis tradicionalmente allâ”śÂˇ ubicada desde hacâ”śÂˇa dâ”śÂ®cadas. Sobre el adoquinado firme perdura el antiguo trazado de la tranviaria lâ”śÂˇnea 13 "San Josâ”śÂ®", que desde 1945 transitâ”śâ”‚ por â”śÂ®l hasta que en 1967 se refundiâ”śâ”‚ con la lâ”śÂˇnea 11 "Parque". Una ligera lluvia ha dejado su huella reflectante en el adoquinado y en los baldosines de la acera. Al fondo, la plaza de Espaâ”śâ–’a.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65171100, -0.87922800, '0101000020E6100000954737C2A222ECBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51548607831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51548607831.webp', 'https://www.flickr.com/photos/zaragozaantigua/51548607831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22853, 'Coso Medio c.1988', 'Calle del Coso en su tramo entre plaza de Espaâ”śâ–’a y Espartero, que en esta recopilaciâ”śâ”‚n hemos dado en bautizar "Coso Medio", para diferenciarlo del Alto (Câ”śÂ®sar Augusto-Plaza de Espaâ”śâ–’a) y el Bajo (Espartero-Tenerâ”śÂˇas). A la izquierda, el Teatro Principal y el Banco de Santander. A la derecha, cubierto por vallas publicitarias, el edificio del Colegio de Santa Ana, ya abandonado y a la espera de derribo y sustituciâ”śâ”‚n por el Hotel Reino de Aragâ”śâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1577428155818748&set=...', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65167100, -0.87948300, '0101000020E61000003C6A4C88B924ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295663888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295663888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295663888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22863, 'San Gil 1987', 'Luis Mâ”śÂˇnguez. 1987. Imagen hacia el Oeste, desde la torre de la Iglesia del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s mâ”śĂ­s cercana al Teatro Romano, en la plaza de San Pedro Nolasco. La visual se centra en la torre de la iglesia de San Gil Abad (la iglesia, en Don Jaime I; la torre, en Estâ”śÂ®banes), antes de su restauraciâ”śâ”‚n, con un aspecto muy deslucido. Un poco antes, a la izquierda, uno de los remates del tejado de la que fue sede central de una entidad local de ahorro, entre la calle San Andrâ”śÂ®s y San Jorge. A la derecha, un poco mâ”śĂ­s adelante, la galerâ”śÂˇa de arquillos de las traseras del Casino Mercantil, en la calle Cuatro de Agosto. Al fondo, dos identificativos edificios de la plaza San Roque, junto al Coso Alto: el edificio de la "Adriâ”śĂ­tica de Seguros" (1948), a la derecha, y el torreâ”śâ”‚n del entonces Banco Central, que en 1970 habâ”śÂˇa absorbido al Banco de Aragâ”śâ”‚n (1945), cuya sede central era esa.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15659392618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15659392618.webp', 'https://www.flickr.com/photos/zaragozaantigua/15659392618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22872, 'Teatro romano 1987', 'Luis Mâ”śÂˇnguez. 1987. Imagen hacia el Sur desde la torre de la Iglesia del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s mâ”śĂ­s cercana al Teatro Romano, en la plaza de San Pedro Nolasco. En 1972, este espacio estaba destinado a ser la sede central de una entidad local de ahorro, pero la publicidad del descubrimiento de los restos del Teatro torcieron el destino, y desde entonces el solar quedâ”śâ”‚ en estas condiciones, tras las primeras excavaciones arqueolâ”śâ”‚gicas. A la derecha, tejado del edificio de San Jorge 12-14, que fue casa palaciega renacentista del Justicia Mayor en el s.XVI, muy reformada a mediados del s.XVIII. Aâ”śâ–’os despuâ”śÂ®s de tomar esta imagen (1995) la Comisiâ”śâ”‚n Provincial de Patrimonio Cultural acordâ”śâ”‚ demolerla para ampliar la zona arqueolâ”śâ”‚gica, y conservar la fachada, luego integrada en el nuevo espacio museâ”śÂˇstico inaugurado en mayo de 2003. Tras la casa, estado de los restos del Teatro romano, con la rampa de bajada de la calle de la Verâ”śâ”‚nica. Pasada la calle, aspecto del dieciochesco edificio esquina con la calle Pardo Sastrâ”śâ”‚n.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15818617806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15818617806.webp', 'https://www.flickr.com/photos/zaragozaantigua/15818617806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26019, 'Isabel la Catâ”śâ”‚lica 1962', 'Imagen en altura del entorno de la Feria de Muestras, a cuya vera fue instalado un Arco de triunfo conmemorativo del "Dâ”śÂˇa de la Hispanidad" durante las Fiestas del Pilar de ese aâ”śâ–’o, justo en el arranque del paseo de Isabel la Catâ”śâ”‚lica. Desde este punto de vista, tomado a la altura de la torre de la Editorial Vives, el naturalizado Arco nos ofrece sus cuartos traseros. En su parte frontal, convivâ”śÂˇan en hispana armonâ”śÂˇa una macedonia de icâ”śâ”‚nicas representaciones con Câ”śÂ®sar Augusto, Alfonso I, Colâ”śâ”‚n, sus Catâ”śâ”‚licas majestades, las tres carabelas, y un amplio y surtido despliegue de banderas americanas. Una imagen para postal de la Editorial Arribas. Fuente: www.delcampe.es/', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24040723341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24040723341.webp', 'https://www.flickr.com/photos/zaragozaantigua/24040723341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22878, 'Calle Porcell 1989', 'Tras el 18 de julio de 1936 el fallido golpe de estado triunfa en Zaragoza, que queda metida en el saco de municipios del Aragâ”śâ”‚n franquista. En 1937, como arma y propaganda de guerra del "Movimiento", aparecen nuevos medios escritos controlados por Falange, entre ellos, el diario "Amanecer", que hasta su desapariciâ”śâ”‚n en junio de 1979 mantuvo una lâ”śÂˇnea editorial de centro liberal, entre la derecha, y la extrema derecha. En mayo de 1989 el inmueble del diario, situado en la calle Porcel nâ”¬â•‘ 1, seguâ”śÂˇa en desuso y fue ocupado por el reciente COZ ("Colectivo Okupa de Zaragoza"). Este acto durâ”śâ”‚ doce dâ”śÂˇas, durante los cuales se comenzâ”śâ”‚ a adecentar el local, hasta el desalojo realizado por antidisturbios de la Policâ”śÂˇa Nacional. No hubo detenidos ni multas. En la imagen, aspecto parcial de la fachada del diario ocupado, en la calle Porcell. Fuente: www.zaragozarebelde.org/', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65136600, -0.87908800, '0101000020E610000025CB49287D21ECBFF9DC09F65FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17232817905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17232817905.webp', 'https://www.flickr.com/photos/zaragozaantigua/17232817905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22933, 'Plaza Josâ”śÂ® Sinuâ”śÂ®s 1981', 'Imagen capturada desde la calle Don Jaime I, y centrada en las traseras del Teatro Principal con el aspecto que les habâ”śÂˇa dado Ricardo Magdalena a finales del siglo XIX, rematadas en un espectacular frontâ”śâ”‚n con el escudo municipal, y las representaciones realizadas por Francisco Rallo de las musas Terpsâ”śÂˇcore y Euterpe. Pocos aâ”śâ–’os despuâ”śÂ®s, Pâ”śÂ®rez Latorre remodelarâ”śÂˇa esta fachada, despojâ”śĂ­ndola del frontâ”śâ”‚n, y las musas fueron reubicadas en la fachada principal del Coso. Como una sana aâ”śâ–’adidura, la plaza fue peatonalizada, y el monumento a Josâ”śÂ® Sinuâ”śÂ®s y Urbiola dejâ”śâ”‚ de ser rotonda entre el trâ”śĂ­fico rodado. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65234600, -0.87917300, '0101000020E6100000B2D6506A2F22ECBF95D6DF1280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31853815772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31853815772.webp', 'https://www.flickr.com/photos/zaragozaantigua/31853815772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22974, 'Teatro Romano aâ”śâ–’os 90', 'F. A. Escudero. Foto aâ”śÂ®rea del Teatro Romano de Zaragoza. Aâ”śâ–’os 90 del siglo XX. El Teatro Romano de Caesaraugusta fue uno de los mayores de toda Hispania (capacidad para 6.000 espectadores en una urbe de unos 18.000 habitantes). Edificado en â”śÂ®poca de Tiberio (14-37) y finalizado en â”śÂ®poca de Claudio (41-54), siguiendo el modelo del Teatro Marcelo de Roma. Su estructura, formada por anillos concâ”śÂ®ntricos reforzados por muros radiales, estâ”śĂ­ construida en aglomerado de hormigâ”śâ”‚n de cal y canto y recubierta con placas de piedra caliza. Al no apoyar su graderâ”śÂˇo en ninguna colina, se creâ”śâ”‚ un sistema de galerâ”śÂˇas abovedadas que permite la circulaciâ”śâ”‚n interior. Es el â”śâ•‘nico teatro peninsular con una fosa bajo el escenario para acceso de los actores en ciertos momentos de la obra. Conserva buena parte de sus estructuras, como la cavea, la orchestra, el balteus, hyposcenium, la cripta y los espacios entre los muros radiales de la cavea. Su â”śÂ®poca de mayor esplendor corresponde a las dinastâ”śÂˇas Julio-Claudia y Flavia (siglo I). En el siglo III es abandonado, expoliado y sus ruinas se reaprovechan como cimientos de viviendas posteriores, e incluso aparecen restos de una necrâ”śâ”‚polis visigâ”śâ”‚tica. Como teatro, permaneciâ”śâ”‚ oculto bajo el urbanismo de la ciudad. Fue redescubierto en 1972, cuando un vecino alertâ”śâ”‚ a la prensa de la existencia de restos arqueolâ”śâ”‚gicos en una obra en construcciâ”śâ”‚n. En la imagen aparece sin la estructura que lo cubre hoy, colocada en 2003. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65198200, -0.87767800, '0101000020E6100000E4654D2CF015ECBF53CA6B2574D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15067104262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15067104262.webp', 'https://www.flickr.com/photos/zaragozaantigua/15067104262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22982, 'Teatro Romano 1992', 'Desde la torre de la Iglesia del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s imagen del Teatro Romano. A la izquierda, pegado a la iglesia, las construcciones de la Hermandad del Santo Refugio diseâ”śâ–’adas por Josâ”śÂ® de Yarza en 1908. A la derecha, patio y tejado de la que fue casa palaciega renacentista del Justicia Mayor en el s.XVI, muy reformada a mediados del s.XVIII. Tras la casa, estado de los restos del Teatro romano, con la rampa de bajada de la calle de la Verâ”śâ”‚nica, con su muro y sus frondosos â”śĂ­rboles. Fuente: "Zaragoza barrio a barrio"', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15945592091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15945592091.webp', 'https://www.flickr.com/photos/zaragozaantigua/15945592091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23015, 'Calle San Jorge aâ”śâ–’os 90', 'Vista del edificio del nâ”śâ•‘mero 12 de la calle de San Jorge, desde la plaza de San Pedro Nolasco. El inmueble, propiedad de Arturo Guillâ”śÂ®n y Urzâ”śĂ­iz, fue rehabilitado como Museo del Teatro Romano de Zaragoza en 2003. Fuente: www.eszaragoza.eu/2017/06/opiniones-de-zaragozanos-de-198...', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65258200, -0.87733900, '0101000020E6100000C72B103D2913ECBFA9FA95CE87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35705560164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35705560164.webp', 'https://www.flickr.com/photos/zaragozaantigua/35705560164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22145, 'Paseo Isabel la Catâ”śâ”‚lica aâ”śâ–’os 50', 'Foto: Colecciâ”śâ”‚n Sergio Joven. Grupo de muchachas apostadas en el pretil del râ”śÂˇo Huerva, junto al quiosco esquinero con el puente del 13 de Septiembre de acceso al parque Primo de Rivera, desde el que estâ”śĂ­ tomada la foto. Al fondo, edificios de la Feria de Muestras. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63740700, -0.89810100, '0101000020E61000001C28F04E3EBDECBFE99E758D96D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26300037300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26300037300.webp', 'https://www.flickr.com/photos/zaragozaantigua/26300037300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22150, 'Parque Primo de Rivera 1956', 'Foto: Josâ”śÂ® Antonio Duce. Febrero de 1956. Aspecto helado del estanque conocido como "la piscina del huevo", sito en el parque Primo de Rivera, junto a la pista de patinaje equipada con un mapa de Espaâ”śâ–’a en relieve. Fuente: www.gozazaragoza.com/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63399900, -0.89736000, '0101000020E610000049A297512CB7ECBF2E5915E126D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27604751734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27604751734.webp', 'https://www.flickr.com/photos/zaragozaantigua/27604751734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23020, 'Calle de San Jorge 1990', 'Imagen capturada en la plaza de San Pedro Nolasco y centrada en la fachada del nâ”¬â•‘ 12-14 de la calle de San Jorge, que fuera original casona renacentista del Justicia Mayor del reino de Aragâ”śâ”‚n a finales del siglo XVI, muy reformada a mediados del XVIII, y nuevamente remozada a mediados del XIX. Aâ”śâ–’os despuâ”śÂ®s de esta toma fotogrâ”śĂ­fica, el solar de la casa fue derribado durante las obras de despeje de la "scaena" del inmediato teatro romano de Caesaraugusta, conservando la fachada integrada en un nuevo edificio destinado a diversos servicios del Museo del Teatro de Caesaragusta e inaugurado en 2003. En primer tâ”śÂ®rmino, la plaza de San Pedro Nolasco en la â”śÂ®poca de la hegemonâ”śÂˇa del trâ”śĂ­fico rodado en estado de reposo. Hacia la izquierda queda la iglesia del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s (donde antes estuviera la iglesia del colegio de San Pedro Nolasco). Hacia la derecha queda la antigua calle de Gabriel Zaporta, perenne recuerdo de la monumental y derribada casa homâ”śâ”‚nima. Fuente visual: AMZ.', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.65258200, -0.87733900, '0101000020E6100000C72B103D2913ECBFA9FA95CE87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42289206005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42289206005.webp', 'https://www.flickr.com/photos/zaragozaantigua/42289206005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23065, 'Calle del Refugio 1997', 'Imagen centrada en el ingreso al singular local El Monaguillo, en los bajos del inmueble del nâ”¬â•‘ 4-6 de la calle del Refugio. Este bar, ubicado en las bodegas de esta antigua casa del siglo XVII, fue hasta su cierre un emblemâ”śĂ­tico y recoleto espacio conocido por la nocturna programaciâ”śâ”‚n de conciertos en directo. Este inmueble serâ”śÂˇa rehabilitado integralmente pocos aâ”śâ–’os despuâ”śÂ®s, conservando las bodegas y la colorista fachada con su ajedrezado cerâ”śĂ­mico.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65331400, -0.87773600, '0101000020E61000000BB3D0CE6916ECBF6D020CCB9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50512217313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50512217313.webp', 'https://www.flickr.com/photos/zaragozaantigua/50512217313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23449, 'Montserrat Caballâ”śÂ® 1973', 'Archivo Municipal Zaragoza. Josâ”śÂ® Jaria Serrano. 26/05/1973. Imagen del Teatro Principal durante la representaciâ”śâ”‚n de la â”śâ”‚pera "Il Trovatore" de Verdi, a cargo de (por orden escâ”śÂ®nico) Franco Bordoni, Bianca Berini, Montserrat Caballâ”śÂ® y Bernabâ”śÂ® Martâ”śÂˇ. "El trovador" (Il trovatore) es una â”śâ”‚pera en cuatro actos con mâ”śâ•‘sica de Giuseppe Verdi y libreto en italiano de Salvatore Cammarano, basada en la obra de teatro "El trovador" (1836) de Antonio Garcâ”śÂˇa Gutiâ”śÂ®rrez. La trama -intrincada y novelesca- se desarrolla entre Vizcaya y Aragâ”śâ”‚n en el marco de la revuelta de Jaime de Urgel, a principios del siglo XV, contra Fernando de Antequera, tras el Compromiso de Caspe. El castillo de La Aljaferâ”śÂˇa es marco escâ”śÂ®nico central de la trama. Montserrat Caballâ”śÂ® y Bernabâ”śÂ® Martâ”śÂˇ eran tambiâ”śÂ®n pareja sentimental desde hacâ”śÂˇa mâ”śĂ­s de diez aâ”śâ–’os, y Bernabâ”śÂ® era maâ”śâ–’o. Ella, catalana.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65203000, -0.87945400, '0101000020E6100000A8C30AB77C24ECBF650113B875D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15076424110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15076424110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15076424110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23499, 'Coso y pavos 1861', 'Calle del Coso y plaza de la Constituciâ”śâ”‚n. "Vista de la calle del Coso en direcciâ”śâ”‚n a la plaza de la Constituciâ”śâ”‚n, que quedarâ”śÂˇa a la derecha de la imagen. Aunque a nuestros ojos resulta prâ”śĂ­cticamente imperceptible, la mancha oscura que queda en el centro de la calzada, no es sino un rebaâ”śâ–’o de pavos junto a su vendedor. Durante el siglo XIX y primera mitad del siglo XX, los vendedores de pavos procedentes de pueblos cercanos, se acercaban hasta el centro de la ciudad para ofrecer su producto en la cercanâ”śÂˇa de las fechas navideâ”śâ–’as, por lo que podemos conjeturar que la fotografâ”śÂˇa pudo ser realizada en las Navidades de 1860-1861." Josâ”śÂ® Antonio Hernâ”śĂ­ndez Latas. Fuente: Mariano Jâ”śâ•‘dez y Ortiz. â”śĂĽlbum de Andrâ”śÂ®s Martâ”śÂˇn e Ipâ”śĂ­s. Colecciâ”śâ”‚n Mariano Martâ”śÂˇn Casalderrey. Libro Primeros tiempos de la fotografâ”śÂˇa en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65133400, -0.87849300, '0101000020E61000004A7A185A9D1CECBFED629AE95ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874371526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874371526.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874371526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23600, 'Lâ”śÂˇnea 13 Tranvâ”śÂˇa 1945', 'Lâ”śÂˇnea 13 de los Tranvâ”śÂˇas de Zaragoza. El Coche 201 en la parada de principio de Lâ”śÂˇnea, situada en la calle Eugenio Blasco. El edificio tras el tranvâ”śÂˇa es el del Teatro Principal, y la calle del fondo, la de Verâ”śâ”‚nica, que entonces era bastante mâ”śĂ­s estrecha de lo que ahora es, hasta que se derribaron los edificios de los nâ”śâ•‘meros impares. A raâ”śÂˇz de eso, aâ”śâ–’os despuâ”śÂ®s, saldrâ”śÂˇa a la luz el Teatro Romano... La Lâ”śÂˇnea 13 se conocâ”śÂˇa como "la de S. Josâ”śÂ®", pues comunicaba "el centro" son este Barrio por medio del tranvâ”śÂˇa, siguiendo el trayecto de ida-vuelta Eugenio Blasco-Coso-Espartero-Pza. S. Miguel-Miguel Servet-Avda. J. Josâ”śÂ®, terminando al lado del Cine Rialto. Proyectada desde 1927, fue realidad en 1945. En 1967 se unificâ”śâ”‚ con la Lâ”śÂˇnea 11, "Parque", tomando su numero, y creando la denominaciâ”śâ”‚n "Parque-S. Josâ”śÂ®". Tras ser tristemente clausurada el 23 de enero de 1976, la lâ”śÂˇnea se transfigurâ”śâ”‚ en el recorrido "de toda la vida" del Autobâ”śâ•‘s Urbano nâ”¬â•‘ 40. Fuente: "Los tranvâ”śÂˇas de Zaragoza", J. Peâ”śâ–’a/J. M. Valero, DPZ, 1985.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.65194300, -0.87899700, '0101000020E610000010070951BE20ECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14673965999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14673965999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14673965999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23601, 'Teatro Principal c.1900', 'Teatro Principal de Zaragoza (1799), reformado en 1870 por Ricardo Magdalena, a quien se debe la fachada que aquâ”śÂˇ aparece. A la izquierda, el inmueble del nâ”¬â•‘ 61, donde estaba radicada la redacciâ”śâ”‚n, imprenta y administraciâ”śâ”‚n de El Diario de Zaragoza, ademâ”śĂ­s del Colegio de San Josâ”śÂ® con su aulario para "Seâ”śâ–’oritos" y para "Seâ”śâ–’oritas".', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65179100, -0.87941600, '0101000020E61000004888F2052D24ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750439809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750439809.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750439809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23602, 'Plazuela de la Verâ”śâ”‚nica 1949', 'Al final de la original calle de la Verâ”śâ”‚nica, donde desemboca en la de Pedro Joaquâ”śÂˇn Soler (a la izquierda, fuera de plano), se encontraba la recoleta plazuela de la Verâ”śâ”‚nica, un espacio caracterâ”śÂˇstico del antiguo Casco Viejo, a resguardo de cierzo, con solanera invernal, y fresquera en verano. Las obras de ampliaciâ”śâ”‚n de las calles de la Verâ”śâ”‚nica y de Pedro Joaquâ”śÂˇn Soler, supusieron su extinciâ”śâ”‚n. De derecha a izquierda, los antiguos edificios de los nâ”śâ•‘meros 1, 2-3, y 4 de la desaparecida plaza. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65148700, -0.87742500, '0101000020E61000006B2BF697DD13ECBF74620FED63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817801109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817801109.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817801109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
